type LayoutVersion = 1 | 2;

type Breakpoint = 'desktop' | 'tablet' | 'mobile';

interface GridConfig {
  columns: number;       // e.g. 12 desktop, 6 tablet, 1 mobile
  rowHeight: number;     // pixel height per logical row
  gap: number;           // pixel gap between widgets
}

interface WidgetLayout {
  id: string;
  x: number;             // column index in logical grid units
  y: number;             // row index in logical grid units
  width: number;         // columns occupied
  height: number;        // rows occupied
  minWidth: number;
  minHeight: number;
  version: LayoutVersion;
}

const persistedWidget = {
  id: 'revenue-chart',
  x: 0,
  y: 0,
  width: 6,
  height: 3,
  minWidth: 3,
  minHeight: 2,
  version: 2
};

interface DashboardSnapshot {
  version: LayoutVersion;
  layouts: Partial<Record<Breakpoint, WidgetLayout[]>>;
  updatedAt: string;
}

interface InteractionState {
  activeId: string | null;
  mode: 'idle' | 'drag' | 'resize' | 'keyboard-move' | 'keyboard-resize';
  startRect?: WidgetLayout;
  candidateRect?: WidgetLayout;
}
